import { CommonModule } from "@angular/common";
import { Component, HostListener, computed, inject } from "@angular/core";
import { Router, RouterLink, RouterLinkActive, RouterOutlet } from "@angular/router";
import { AuthService } from "./services/auth.service";

@Component({
  selector: "app-root",
  standalone: true,
  imports: [CommonModule, RouterOutlet, RouterLink, RouterLinkActive],
  templateUrl: "./app.component.html",
  styleUrl: "./app.component.css"
})
export class AppComponent {
  private readonly authService = inject(AuthService);
  private readonly router = inject(Router);

  readonly session = this.authService.session;
  readonly isStudent = computed(() => this.session()?.role === "STUDENT");
  readonly isLecturer = computed(() => this.session()?.role === "LECTURER");
  showUserMenu = false;

  isLoginPage(): boolean {
    return this.router.url.startsWith("/login");
  }

  headerTitle(): string {
    if (this.router.url.startsWith("/lecturer/dashboard")) {
      return "Lecturer Dashboard";
    }
    if (this.router.url.startsWith("/lecturer/manage")) {
      return "Course Content";
    }
    if (this.router.url.startsWith("/lecturer/monitoring")) {
      return "Student Monitoring";
    }
    if (this.router.url.startsWith("/lecturer/question-bank")) {
      return "Quiz Builder";
    }
    if (this.router.url.startsWith("/student/dashboard")) {
      return "";
    }
    if (this.router.url.startsWith("/student/history")) {
      return "Attempt History";
    }
    if (this.router.url.startsWith("/student/courses/")) {
      return "Course Learning";
    }
    if (this.router.url.startsWith("/student/quiz/")) {
      return "Quiz Session";
    }
    return "EduSIM Portal";
  }

  toggleUserMenu(event: Event): void {
    event.stopPropagation();
    this.showUserMenu = !this.showUserMenu;
  }

  closeMenus(): void {
    this.showUserMenu = false;
  }

  @HostListener("document:click")
  onDocumentClick(): void {
    this.closeMenus();
  }

  navigateHome(): void {
    this.closeMenus();
    if (this.isLecturer()) {
      this.router.navigateByUrl("/lecturer/dashboard");
      return;
    }
    if (this.isStudent()) {
      this.router.navigateByUrl("/student/dashboard");
      return;
    }
    this.router.navigateByUrl("/login");
  }

  openQuickSearch(): void {
    this.closeMenus();
    if (this.isLecturer()) {
      this.router.navigateByUrl("/lecturer/monitoring");
      return;
    }
    this.router.navigateByUrl("/student/dashboard");
  }

  logout(): void {
    this.closeMenus();
    this.authService.logout();
    this.router.navigateByUrl("/login");
  }
}
@if (!isLoginPage()) {
  <header class="portal-shell">
    <div class="top-strip">
      <div class="container top-strip-inner">
        <button class="brand-wrap" type="button" (click)="navigateHome()" aria-label="Go to EduSIM home">
          <img class="brand-logo" src="assets/edusim-logo.svg" alt="EduSIM logo" />
          <div class="brand-copy">
            <span class="brand-title">Educational Self-Instructional Material System</span>
          </div>
        </button>

        @if (session(); as user) {
          <div class="top-actions">
            <button class="icon-btn top-icon" type="button" aria-label="Notifications">
              <svg viewBox="0 0 24 24" aria-hidden="true">
                <path d="M12 2a6 6 0 0 0-6 6v3.6L4.2 14a1 1 0 0 0 .8 1.6h14a1 1 0 0 0 .8-1.6L18 11.6V8a6 6 0 0 0-6-6zm0 20a3 3 0 0 0 2.8-2h-5.6A3 3 0 0 0 12 22z"></path>
              </svg>
            </button>
            <button class="icon-btn top-icon" type="button" aria-label="Messages">
              <svg viewBox="0 0 24 24" aria-hidden="true">
                <path d="M4 4h16a2 2 0 0 1 2 2v8a2 2 0 0 1-2 2H8l-5 4v-4H4a2 2 0 0 1-2-2V6a2 2 0 0 1 2-2z"></path>
              </svg>
            </button>

            <div class="menu-wrap user-wrap" (click)="$event.stopPropagation()">
              <button class="user-chip" type="button" aria-label="User Menu" (click)="toggleUserMenu($event)">
                <span class="user-name">{{ user.fullName }}</span>
                <span class="user-avatar">{{ (user.fullName || "U").charAt(0) | uppercase }}</span>
              </button>
              @if (showUserMenu) {
                <div class="menu-dropdown user-dropdown">
                  <div class="menu-user">{{ user.fullName }}</div>
                  <button type="button" (click)="navigateHome()">Go to Home</button>
                  <button type="button" (click)="logout()">Logout</button>
                </div>
              }
            </div>
          </div>
        }
      </div>
    </div>

    @if (session()) {
      <div class="nav-strip">
        <div class="container nav-strip-inner">
          <nav class="portal-nav" aria-label="Main menu">
            <button class="nav-link-btn" type="button" (click)="navigateHome()">Home</button>
            @if (isLecturer()) {
              <a routerLink="/lecturer/dashboard" routerLinkActive="active-link">Dashboard</a>
              <a routerLink="/lecturer/manage" routerLinkActive="active-link">My Courses</a>
              <a routerLink="/lecturer/monitoring" routerLinkActive="active-link">Student Monitoring</a>
            }
            @if (isStudent()) {
              <a routerLink="/student/dashboard" routerLinkActive="active-link">Dashboard</a>
              <a routerLink="/student/dashboard" routerLinkActive="active-link">My Courses</a>
              <a routerLink="/student/history" routerLinkActive="active-link">Previous Session</a>
            }
          </nav>

          <button class="icon-btn search-btn" type="button" aria-label="Search" (click)="openQuickSearch()">
            <svg viewBox="0 0 24 24" aria-hidden="true">
              <path d="M15.5 14h-.8l-.3-.3a6 6 0 1 0-.7.7l.3.3v.8L19 20l1-1-4.5-5zM10 15a5 5 0 1 1 0-10 5 5 0 0 1 0 10z"></path>
            </svg>
          </button>
        </div>
      </div>
    }
  </header>
}

<main class="page" [class.page-login]="isLoginPage()">
  <router-outlet />
</main>
